#include <stdio.h>

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        if (N % 2 == 1) {
            printf("-1\n");
            continue;
        }
        for (int i = 1; i <= N; i += 2) {
            printf("%d %d", i + 1, i);
            if (i + 2 <= N) printf(" ");
        }
        printf("\n");
    }
    return 0;
}

